1→import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
2→import { X, Palette, Link2, Trash2, Type, Plus, Minus, Save, FileDown, Grid3X3, AlignLeft, AlignCenter, AlignRight, Expand, Shrink } from 'lucide-react';
3→
4→const COLORS = [
5→  '#ff3131', '#ff6b35', '#ffea00', '#39ff14', '#00d2ff', '#a855f7', '#ec4899',
6→  '#ffffff', '#94a3b8', '#1e293b', '#000000', '#7c3aed', '#06b6d4', '#84cc16',
7→];
8→
9→const CELL_COLORS = [
10→  { label: 'Qizil', value: 'rgba(255,49,49,0.25)' },
11→  { label: 'Yashil', value: 'rgba(57,255,20,0.2)' },
12→  { label: 'Ko\'k', value: 'rgba(0,210,255,0.2)' },
13→  { label: 'Sariq', value: 'rgba(255,234,0,0.2)' },
14→  { label: 'Binafsha', value: 'rgba(168,85,247,0.2)' },
15→  { label: 'Pushti', value: 'rgba(236,72,153,0.2)' },
16→  { label: 'Tozalash', value: 'transparent' },
17→];
18→
19→const FONTS = ['Inter', 'Arial', 'Georgia', 'Courier New', 'Times New Roman'];
20→const SIZES = [10, 12, 14, 16, 18, 20, 24, 28, 32];
21→
22→const DEFAULT_ROWS = 30;
23→const DEFAULT_COLS = 12;
24→const COL_LABELS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
25→
26→function colLabel(c) {
27→  if (c < 26) return COL_LABELS[c];
28→  return COL_LABELS[Math.floor(c / 26) - 1] + COL_LABELS[c % 26];
29→}
30→
31→function cellKey(r, c) {
32→  return `${r}-${c}`;
33→}
34→
35→const ExcelTable = ({ initialData, onSave, machines = [] }) => {
36→  const [rows, setRows] = useState(initialData?.rows || DEFAULT_ROWS);
37→  const [cols, setCols] = useState(initialData?.cols || DEFAULT_COLS);
38→  const [cells, setCells] = useState(initialData?.cells || {});
39→  const [selectedCell, setSelectedCell] = useState(null);
40→  const [selectedRange, setSelectedRange] = useState(null);
41→  const [selectionStart, setSelectionStart] = useState(null);
42→  const [selecting, setSelecting] = useState(false);
43→  const [contextMenu, setContextMenu] = useState(null);
44→  const [editMode, setEditMode] = useState(false);
45→  const [editValue, setEditValue] = useState('');
46→  const [activePanel, setActivePanel] = useState(null);
47→  const [title, setTitle] = useState(initialData?.title || 'Yangi Hisobot');
48→  const [colWidths, setColWidths] = useState(() => {
49→    const saved = initialData?.colWidths;
50→    return saved || {};
51→  });
52→  const [rowHeights, setRowHeights] = useState(() => {
53→    const saved = initialData?.rowHeights;
54→    return saved || {};
55→  });
56→  const [autoResize, setAutoResize] = useState(false);
57→  const [resizing, setResizing] = useState(null);
58→  const [resizeStart, setResizeStart] = useState(null);
59→  const tableRef = useRef(null);
60→  const editRef = useRef(null);
61→  const measureRef = useRef(null);
62→
63→  const getCell = useCallback((r, c) => {
64→    return cells[cellKey(r, c)] || { value: '', style: {} };
65→  }, [cells]);
66→
67→  const updateCell = useCallback((r, c, updates) => {
68→    setCells(prev => {
69→      const key = cellKey(r, c);
70→      const existing = prev[key] || { value: '', style: {} };
71→      return { ...prev, [key]: { ...existing, ...updates } };
72→    });
73→  }, []);
74→
75→  // Measure text width using canvas
76→  const measureText = useCallback((text, fontSize = 13, fontFamily = 'Inter', fontWeight = 400) => {
77→    if (!measureRef.current) {
78→      measureRef.current = document.createElement('canvas').getContext('2d');
79→    }
80→    const ctx = measureRef.current;
81→    ctx.font = `${fontWeight === 700 ? 'bold ' : ''}${fontSize}px ${fontFamily}`;
82→    return ctx.measureText(text).width;
83→  }, []);
84→
85→  // Auto-resize column based on content
86→  const autoResizeColumn = useCallback((colIdx) => {
87→    let maxWidth = 40;
88→    for (let r = 0; r < rows; r++) {
89→      const cell = getCell(r, colIdx);
90→      const val = String(cell.value || '');
91→      if (!val) continue;
92→      const fontSize = cell.style?.fontSize || 13;
93→      const fontWeight = cell.style?.fontWeight || 400;
94→      const fontFamily = cell.style?.fontFamily || 'Inter';
95→      const lines = val.split('\n');
96→      for (const line of lines) {
97→        const w = measureText(line, fontSize, fontFamily, fontWeight);
98→        maxWidth = Math.max(maxWidth, w + 16);
99→      }
100→    }
101→    setColWidths(prev => ({ ...prev, [colIdx]: Math.ceil(maxWidth) }));
102→  }, [rows, getCell, measureText]);
103→
104→  // Auto-resize row based on content
105→  const autoResizeRow = useCallback((rowIdx) => {
106→    let maxHeight = 36;
107→    for (let c = 0; c < cols; c++) {
108→      const cell = getCell(rowIdx, c);
109→      const val = String(cell.value || '');
110→      if (!val) continue;
111→      const fontSize = cell.style?.fontSize || 13;
112→      const lines = val.split('\n');
113→      const cellWidth = colWidths[c] || 80;
114→      let totalLines = 0;
115→      for (const line of lines) {
116→        const w = measureText(line, fontSize, cell.style?.fontFamily || 'Inter', cell.style?.fontWeight || 400);
117→        totalLines += Math.max(1, Math.ceil(w / (cellWidth - 12)));
118→      }
119→      const h = totalLines * (fontSize + 4) + 16;
120→      maxHeight = Math.max(maxHeight, h);
121→    }
122→    setRowHeights(prev => ({ ...prev, [rowIdx]: Math.ceil(maxHeight) }));
123→  }, [cols, getCell, colWidths, measureText]);
124→
125→  // Auto-resize all
126→  const autoResizeAll = useCallback(() => {
127→    for (let c = 0; c < cols; c++) autoResizeColumn(c);
128→    for (let r = 0; r < rows; r++) autoResizeRow(r);
129→  }, [cols, rows, autoResizeColumn, autoResizeRow]);
130→
131→  // When auto-resize is on and cells change, resize all
132→  useEffect(() => {
133→    if (autoResize) {
134→      autoResizeAll();
135→    }
136→  }, [cells, autoResize, autoResizeAll]);
137→
138→  const getSelectedCells = useCallback(() => {
139→    if (selectedRange) {
140→      const res = [];
141→      const r1 = Math.min(selectedRange.r1, selectedRange.r2);
142→      const r2 = Math.max(selectedRange.r1, selectedRange.r2);
143→      const c1 = Math.min(selectedRange.c1, selectedRange.c2);
144→      const c2 = Math.max(selectedRange.c1, selectedRange.c2);
145→      for (let r = r1; r <= r2; r++) {
146→        for (let c = c1; c <= c2; c++) {
147→          res.push({ r, c });
148→        }
149→      }
150→      return res;
151→    }
152→    if (selectedCell) return [selectedCell];
153→    return [];
154→  }, [selectedCell, selectedRange]);
155→
156→  const handleCellClick = (r, c, e) => {
157→    if (e.shiftKey && selectedCell) {
158→      setSelectedRange({
159→        r1: selectedCell.r, c1: selectedCell.c,
160→        r2: r, c2: c
161→      });
162→      setSelectedCell(null);
163→    } else {
164→      setSelectedCell({ r, c });
165→      setSelectedRange(null);
166→    }
167→    setContextMenu(null);
168→    setActivePanel(null);
169→  };
170→
171→  const handleCellMouseDown = (r, c, e) => {
172→    if (e.button === 0 && !e.shiftKey) {
173→      setSelecting(true);
174→      setSelectionStart({ r, c });
175→    }
176→  };
177→
178→  const handleCellMouseEnter = (r, c) => {
179→    if (selecting && selectionStart) {
180→      setSelectedCell(null);
181→      setSelectedRange({
182→        r1: selectionStart.r, c1: selectionStart.c,
183→        r2: r, c2: c
184→      });
185→    }
186→  };
187→
188→  const handleMouseUp = () => {
189→    setSelecting(false);
190→    setSelectionStart(null);
191→    if (resizing) {
192→      setResizing(null);
193→      setResizeStart(null);
194→    }
195→  };
196→
197→  useEffect(() => {
198→    document.addEventListener('mouseup', handleMouseUp);
199→    return () => document.removeEventListener('mouseup', handleMouseUp);
200→  }, []);
201→
202→  const handleCellDoubleClick = (r, c) => {
203→    const cell = getCell(r, c);
204→    setEditValue(cell.value || '');
205→    setEditMode(true);
206→    setTimeout(() => editRef.current?.focus(), 10);
207→  };
208→
209→  const handleEditFinish = () => {
210→    if (selectedCell) {
211→      updateCell(selectedCell.r, selectedCell.c, { value: editValue });
212→    }
213→    setEditMode(false);
214→  };
215→
216→  const handleContextMenu = (r, c, e) => {
217→    e.preventDefault();
218→    setSelectedCell({ r, c });
219→    setSelectedRange(null);
220→    setContextMenu({
221→      x: Math.min(e.clientX, window.innerWidth - 220),
222→      y: Math.min(e.clientY, window.innerHeight - 300),
223→    });
224→  };
225→
226→  const handleKeyDown = (e) => {
227→    if (!selectedCell) return;
228→    if (editMode) {
229→      if (e.key === 'Enter' && !e.shiftKey) { handleEditFinish(); e.preventDefault(); }
230→      if (e.key === 'Escape') { setEditMode(false); e.preventDefault(); }
231→      return;
232→    }
233→    let { r, c } = selectedCell;
234→    if (e.key === 'ArrowUp') r = Math.max(0, r - 1);
235→    else if (e.key === 'ArrowDown') r = Math.min(rows - 1, r + 1);
236→    else if (e.key === 'ArrowLeft') c = Math.max(0, c - 1);
237→    else if (e.key === 'ArrowRight') c = Math.min(cols - 1, c + 1);
238→    else if (e.key === 'Enter') { handleCellDoubleClick(r, c); return; }
239→    else if (e.key === 'Delete' || e.key === 'Backspace') {
240→      getSelectedCells().forEach(({ r, c }) => updateCell(r, c, { value: '' }));
241→      return;
242→    } else if (e.key.length === 1 && !e.ctrlKey && !e.metaKey) {
243→      setEditValue(e.key);
244→      setEditMode(true);
245→      setTimeout(() => editRef.current?.focus(), 10);
246→      return;
247→    } else return;
248→    e.preventDefault();
249→    setSelectedCell({ r, c });
250→    setSelectedRange(null);
251→  };
252→
253→  // Column resize
254→  const handleColResizeStart = (colIdx, e) => {
255→    e.stopPropagation();
256→    e.preventDefault();
257→    setResizing({ type: 'col', index: colIdx });
258→    setResizeStart({ x: e.clientX, y: e.clientY, origSize: colWidths[colIdx] || 80 });
259→  };
260→
261→  // Row resize
262→  const handleRowResizeStart = (rowIdx, e) => {
263→    e.stopPropagation();
264→    e.preventDefault();
265→    setResizing({ type: 'row', index: rowIdx });
266→    setResizeStart({ x: e.clientX, y: e.clientY, origSize: rowHeights[rowIdx] || 36 });
267→  };
268→
269→  useEffect(() => {
270→    if (!resizing || !resizeStart) return;
271→    const handleMouseMove = (e) => {
272→      if (resizing.type === 'col') {
273→        const delta = e.clientX - resizeStart.x;
274→        const newWidth = Math.max(30, resizeStart.origSize + delta);
275→        setColWidths(prev => ({ ...prev, [resizing.index]: newWidth }));
276→      } else {
277→        const delta = e.clientY - resizeStart.y;
278→        const newHeight = Math.max(20, resizeStart.origSize + delta);
279→        setRowHeights(prev => ({ ...prev, [resizing.index]: newHeight }));
280→      }
281→    };
282→    const handleMouseUp2 = () => {
283→      setResizing(null);
284→      setResizeStart(null);
285→    };
286→    document.addEventListener('mousemove', handleMouseMove);
287→    document.addEventListener('mouseup', handleMouseUp2);
288→    return () => {
289→      document.removeEventListener('mousemove', handleMouseMove);
290→      document.removeEventListener('mouseup', handleMouseUp2);
291→    };
292→  }, [resizing, resizeStart]);
293→
294→  const applyStyleToSelection = (styleUpdate) => {
295→    getSelectedCells().forEach(({ r, c }) => {
296→      const cell = getCell(r, c);
297→      updateCell(r, c, { style: { ...cell.style, ...styleUpdate } });
298→    });
299→    setActivePanel(null);
300→    setContextMenu(null);
301→  };
302→
303→  const deleteCells = () => {
304→    getSelectedCells().forEach(({ r, c }) => updateCell(r, c, { value: '', style: {} }));
305→    setContextMenu(null);
306→  };
307→
308→  const addRow = () => setRows(prev => prev + 5);
309→  const removeRow = () => setRows(prev => Math.max(5, prev - 1));
310→  const addCol = () => setCols(prev => prev + 2);
311→  const removeCol = () => setCols(prev => Math.max(3, prev - 1));
312→
313→  const linkToMachine = (machineId) => {
314→    if (selectedCell) {
315→      updateCell(selectedCell.r, selectedCell.c, {
316→        linkedMachine: machineId,
317→        value: `stanok:${machineId}`,
