319→    }
320→    setActivePanel(null);
321→    setContextMenu(null);
322→  };
323→
324→  const unlinkMachine = () => {
325→    if (selectedCell) {
326→      updateCell(selectedCell.r, selectedCell.c, {
327→        linkedMachine: null,
328→        value: '',
329→      });
330→    }
331→    setContextMenu(null);
332→  };
333→
334→  const getCurrentShift = () => {
335→    const now = new Date();
336→    const hour = now.getHours();
337→    if (hour >= 7 && hour < 19) return { type: 'KUNDUZ', label: 'Kunduzgi', shift: 1 };
338→    return { type: 'TUN', label: 'Tungi', shift: 2 };
339→  };
340→
341→  const renderCellValue = (r, c) => {
342→    const cell = getCell(r, c);
343→    if (cell.linkedMachine) {
344→      const machine = machines.find(m => m.id === cell.linkedMachine);
